// Generated by hand. Loads active standards and returns them as a checklist.
// Call before declaring any task done.

import { active, byCategory } from '../../../../standards/index.js'

export const definition = {
  id: 'check-standards',
  name: 'Check Standards',
  description: 'Returns applicable coding standards as a checklist. Use before declaring any task done.',
  version: '1.0.0',
  inputs: [
    {
      name: 'category',
      type: 'text',
      label: 'Category filter (optional)',
      required: false,
      description: 'One of: code, architecture, conventions, ui, process, security. Leave blank for all.',
    },
    {
      name: 'appName',
      type: 'text',
      label: 'App name (optional)',
      required: false,
      description: 'If provided, also loads overrides for this app so you know which rules are excepted.',
    },
  ],
}

export async function run(input, _ctx) {
  const category = (input.category || '').trim().toLowerCase()
  const appName  = (input.appName  || '').trim()

  let rules = active
  if (category && byCategory[category]) {
    rules = byCategory[category].filter(r => r.status === 'active')
  }

  let overrideList = []
  if (appName) {
    try {
      const { getOverrides } = await import('../../../../standards/overrides.js')
      overrideList = getOverrides(appName)
    } catch { /* overrides file missing or unreadable — treat as no overrides */ }
  }

  const checklist = rules.map(r => {
    const override = overrideList.find(o => o.ruleId === r.id)
    return {
      id: r.id,
      level: r.level,
      description: r.description,
      overridden: !!override,
      overrideReason: override?.reason ?? null,
    }
  })

  const errors   = checklist.filter(r => r.level === 'error'   && !r.overridden)
  const warnings = checklist.filter(r => r.level === 'warning'  && !r.overridden)
  const skipped  = checklist.filter(r => r.overridden)

  return {
    summary:  `${errors.length} required · ${warnings.length} advisory · ${skipped.length} overridden`,
    errors,
    warnings,
    skipped,
    appName:  appName  || null,
    category: category || 'all',
  }
}

export const tests = [
  {
    name: 'returns rules across all categories when no filter',
    input: {},
    expect: r => r.errors.length > 0 && r.warnings.length > 0,
  },
  {
    name: 'filters by category — security rules only',
    input: { category: 'security' },
    expect: r => [...r.errors, ...r.warnings].every(rule => rule.id.startsWith('security-')),
  },
  {
    name: 'summary string is present',
    input: { category: 'ui' },
    expect: r => typeof r.summary === 'string' && r.summary.includes('·'),
  },
]
